 }

+/* Validate that a GF_Box pointer refers to a genuine registered box with required handlers. */
+Bool gf_isom_box_is_valid(GF_Box *ptr)
+{
+	if (!ptr) return GF_FALSE;
+	if (!ptr->registry) return GF_FALSE;
+	/* registry must reference the same 4cc and provide size and write functions */
+	if (ptr->registry->box_4cc != ptr->type) return GF_FALSE;
+	/* For safety, require at least one of the write/size functions to be present when used as a box */
+	if (!ptr->registry->write_fn || !ptr->registry->size_fn) return GF_FALSE;
+	/* registry should not be disabled */
+	if (ptr->registry->disabled) return GF_FALSE;
+	return GF_TRUE;
+}
